"use strict";(self.webpackChunkmy_blog=self.webpackChunkmy_blog||[]).push([[1477],{10:t=>{t.exports=JSON.parse('{"blogPosts":[{"id":"Interface","metadata":{"permalink":"/blog/Interface","editUrl":"https://github.com/eunchu/blog/tree/main/blog/2022-07-02-interface/index.md","source":"@site/blog/2022-07-02-interface/index.md","title":"Typescript interface \uc27d\uac8c \ub9cc\ub4e4\uae30","description":"\ubc1b\uc544\uc628 api object\uc758 keys, values\ub97c \ubf51\uc544\uc11c \uc27d\uac8c \ubcf5\ubd99\ud574\uc11c \ub9cc\ub4e4\uc790!","date":"2022-07-02T00:00:00.000Z","formattedDate":"2022\ub144 7\uc6d4 2\uc77c","tags":[{"label":"Typescript","permalink":"/blog/tags/typescript"},{"label":"Tip","permalink":"/blog/tags/tip"}],"readingTime":0.565,"truncated":true,"authors":[{"name":"Eunju","title":"Front End Engineer","url":"https://github.com/eunchu","imageURL":"https://github.com/eunchu.png","key":"eunju"}],"frontMatter":{"slug":"Interface","title":"Typescript interface \uc27d\uac8c \ub9cc\ub4e4\uae30","authors":["eunju"],"tags":["Typescript","Tip"]},"nextItem":{"title":"Javascript \uc774\ubca4\ud2b8 \uad00\ub9ac \ubc29\ubc95(\ubc84\ube14\ub9c1,\ucea1\ucc98\ub9c1,\uc704\uc784 \ub4f1)","permalink":"/blog/JSEvent"}},"content":"\ubc1b\uc544\uc628 api object\uc758 keys, values\ub97c \ubf51\uc544\uc11c \uc27d\uac8c \ubcf5\ubd99\ud574\uc11c \ub9cc\ub4e4\uc790!\\n\\n\x3c!--truncate--\x3e\\n\\n\ucf58\uc194\ub85c \ucd9c\ub825\ud55c \ub4a4,<br/>\\n`Store object as global variable` \ud56d\ubaa9\uc744 \ud074\ub9ad\ud558\uba74 `temp1` \uc774\ub780 `object`\uac00 \uc0dd\uc131\ub428\\n\\n![\uc608\uc2dc](./01.png)\\n\\n```typescript\\nObject.keys(temp1).join();\\n\\n> \\"id,name,...\\";\\n```\\n\\n\ubaa8\ub4e0 \uc18d\uc131\uba85 \uac00\uc838\uc624\uae30\\n\\n```typescript\\nObject.values(temp1)\\n  .map((v) => typeof v)\\n  .join();\\n\\n> \\"string,string,...\\";\\n```\\n\\n\ubaa8\ub4e0 \ud0c0\uc785 \uac00\uc838\uc624\uae30\\n\\n_\ub2e8, object in array \uac19\uc740 \uacbd\uc6b0 \uadf8\ub0e5 object\ub85c \ucc0d\ud788\uae30 \ub54c\ubb38\uc5d0.. \ud655\uc778\ud558\uace0 \uc0ac\uc6a9\ud574\uc57c \ud55c\ub2e4!_"},{"id":"JSEvent","metadata":{"permalink":"/blog/JSEvent","editUrl":"https://github.com/eunchu/blog/tree/main/blog/2022-06-10-jsEvent/index.md","source":"@site/blog/2022-06-10-jsEvent/index.md","title":"Javascript \uc774\ubca4\ud2b8 \uad00\ub9ac \ubc29\ubc95(\ubc84\ube14\ub9c1,\ucea1\ucc98\ub9c1,\uc704\uc784 \ub4f1)","description":"\ube44\ub3d9\uae30 \ucc98\ub9ac\uc758 \ud2b9\uc131","date":"2022-06-10T00:00:00.000Z","formattedDate":"2022\ub144 6\uc6d4 10\uc77c","tags":[{"label":"Javascript","permalink":"/blog/tags/javascript"},{"label":"event","permalink":"/blog/tags/event"}],"readingTime":2.6,"truncated":true,"authors":[{"name":"Eunju","title":"Front End Engineer","url":"https://github.com/eunchu","imageURL":"https://github.com/eunchu.png","key":"eunju"}],"frontMatter":{"slug":"JSEvent","title":"Javascript \uc774\ubca4\ud2b8 \uad00\ub9ac \ubc29\ubc95(\ubc84\ube14\ub9c1,\ucea1\ucc98\ub9c1,\uc704\uc784 \ub4f1)","authors":["eunju"],"tags":["Javascript","event"]},"prevItem":{"title":"Typescript interface \uc27d\uac8c \ub9cc\ub4e4\uae30","permalink":"/blog/Interface"},"nextItem":{"title":"Typescript \uc815\ub9ac","permalink":"/blog/typescript"}},"content":"## \ube44\ub3d9\uae30 \ucc98\ub9ac\uc758 \ud2b9\uc131\\n\\n\ud2b9\uc815 \ub85c\uc9c1\uc758 \uc2e4\ud589\uc774 \ub05d\ub0a0 \ub54c\uae4c\uc9c0 \uae30\ub2e4\ub824\uc8fc\uc9c0 \uc54a\uace0 \ub098\uba38\uc9c0 \ucf54\ub4dc\ub97c \uba3c\uc800\\n\uc2e4\ud589\ud558\ub294 \uac83\uc774 \ube44\ub3d9\uae30 \ucc98\ub9ac\uc758 \ud2b9\uc9d5\\n\\n\x3c!--truncate--\x3e\\n\\n## \ube44\ub3d9\uae30 \ucc98\ub9ac\uc758 \ubb38\uc81c\uc810\\n\\n\uc88b\uc740 \uc0ac\uc6a9\uc790 \uacbd\ud5d8\uacfc \uc131\ub2a5\uc744 \uc704\ud574 \ube44\ub3d9\uae30\ucc98\ub9ac \ubc29\uc2dd\uc744 \ucc44\ud0dd\ud558\uace0 \uc788\uc9c0\ub9cc\\n\uac1c\ubc1c\uc790\ub294 \uc21c\uc11c\uac00 \ub4a4\uc8fd\ubc15\uc8fd\uc778 \ucf54\ub4dc\uc758 \uc2e4\ud589\uc774 \uc9c1\uad00\uc801\uc774\uc9c0 \uc54a\uc544 \ubd88\ud3b8\ud558\uace0\\napi\uc751\ub2f5\uc744 \ud1b5\ud574 \ub2e4\uc74c \ucf54\ub4dc\ub97c \uc2e4\ud589\uc2dc\ud0a4\ub294 \ub4f1\uc758 \ub3d9\uae30\uc801 \uc2e4\ud589 \ucc98\ub9ac\uac00 \ud544\uc694\ud558\ub2e4\\n\\n## \uc608\uc678(\uc5d0\ub7ec) \ucc98\ub9ac \ubc29\uc2dd\\n\\n`Promise`\uc758 \uacbd\uc6b0 `.catch()`\ub97c \ud1b5\ud574\uc11c,<br/>\\n`async&await` \ub97c \uc0ac\uc6a9\ud560 \uacbd\uc6b0\uc5d4 `try & catch`\ub97c \ud1b5\ud574 \uc624\ub958\ub97c \uc7a1\ud558\uc900\ub2e4<br/>\\n\uc608\uc678\ucc98\ub9ac\ub97c \uc548\ud560 \uacbd\uc6b0<br/>\\n\uc5d0\ub7ec\ub098 \ub0ac\uc74c\uc5d0\ub3c4 \uc774\ud6c4 \ub85c\uc9c1\uc744 \uacc4\uc18d \uc2e4\ud589\ud558\uae30 \ub54c\ubb38\uc5d0 \uc624\ub958\uac00 \ubc1c\uc0dd\ud568\\n\\n### \uac1c\ub150 \uc815\ub9ac\\n\\n## \uc774\ubca4\ud2b8 \ubc84\ube14\ub9c1(Bubbling)\\n\\n\uc774\ubca4\ud2b8 \ubc1c\uc0dd \uc2dc, \uc694\uc18c\uc5d0 \ud560\ub2f9\ub41c \ud578\ub4e4\ub7ec \ub3d9\uc791 \ud6c4\uc5d0 \ucd5c\uc0c1\ub2e8\uc758 \uc870\uc0c1\uc694\uc18c\ub97c \ub9cc\ub0a0 \ub54c\uae4c\uc9c0 \ubd80\ubaa8\uc694\uc18c \ud578\ub4e4\ub7ec\ub97c \ub3d9\uc791\ud558\ub294 \uac83\\n\\n```typescript\\n<form onClick=\\"alert(\'form\')\\">\\n  <div onClick=\\"alert(\'div\')\\">\\n    <p onClick=\\"alert(\'p\')\\">event</p>\\n  </div>\\n</form>\\n```\\n\\np\ub97c \ud074\ub9ad\ud558\uba74, p,div,form \uc21c\uc73c\ub85c alert\uc774 \ubc1c\uc0dd\ub41c\ub2e4\\n\\n> `e.stopPropagation()` -> \uc704\ucabd\uc73c\ub85c \uc77c\uc5b4\ub098\ub294 \ubc84\ube14\ub9c1\uc744 \ub9c9\uc544\uc90c. (\ub2e4\ub978 \ud578\ub4e4\ub7ec \ub3d9\uc791\uc740 \ubabb\ub9c9)\\n> `e.stopImmediatepropagation()` -> \ub2e4\ub978 \ud578\ub4e4\ub7ec \ub3d9\uc791\ub3c4 \ub9c9\uc544\uc90c\\n\\n## \uc774\ubca4\ud2b8 \ucea1\uccd0\ub9c1(Capturing)\\n\\n\ubc84\ube14\ub9c1\uc758 \ubc18\ub300. \uc774\ubca4\ud2b8\uac00 \ud558\uc704 \uc694\uc18c\ub85c \uc804\ud30c\ub418\ub294 \uac83\\n\\n## \uc774\ubca4\ud2b8 \uc704\uc784\\n\\n\ud558\ub098\uc758 \ubd80\ubaa8\uc5d0 \uc774\ubca4\ud2b8\ub97c \ub4f1\ub85d\ud558\uc5ec, \ubd80\ubaa8\uac00 \uc774\ubca4\ud2b8\ub97c \uc704\uc784\ud558\ub294 \ubc29\uc2dd\\n\ud558\uc704 \uc694\uc18c \uac01\uac01\uc5d0\uc11c \uc774\ubca4\ud2b8\ub97c \ubd99\uc774\uc9c0 \uc54a\uace0 \uc0c1\uc704 \uc694\uc18c\uc5d0\uc11c \ud558\uc704 \uc694\uc18c\ub4e4\uc758 \uc774\ubca4\ud2b8\ub4e4\uc744 \uc81c\uc5b4\ud568\\n\\n**\uc7a5\uc810**\\n\\n- \ub3d9\uc801\uc778 \uc694\uc18c\ub4e4\uc758 \ucc98\ub9ac\uac00 \uc218\uc6d4\ud568\\n- \uc774\ubca4\ud2b8 \ud578\ub4e4\ub7ec\uac00 \ub354 \uc801\uac8c \ub4f1\ub85d\ub418\uae30 \ub54c\ubb38\uc5d0 \uba54\ubaa8\ub9ac \uc808\uc57d\\n- \ud558\uc704 \uc694\uc18c\uac00 \ub9ce\uc544\uc9c8\uc218\ub85d \uc774\ubca4\ud2b8\ub9ac\uc2a4\ub108\ub97c \ub2e4\ub8e8\ub294 \uc791\uc5c5\uc774 \ubc88\uac70\ub86d\uae30 \ub54c\ubb38\uc5d0 \uc704\uc784\ubc29\uc2dd\uc744 \uc0ac\uc6a9\ud568"},{"id":"typescript","metadata":{"permalink":"/blog/typescript","editUrl":"https://github.com/eunchu/blog/tree/main/blog/2022-06-04-typescript/index.md","source":"@site/blog/2022-06-04-typescript/index.md","title":"Typescript \uc815\ub9ac","description":"Typescript","date":"2022-06-04T00:00:00.000Z","formattedDate":"2022\ub144 6\uc6d4 4\uc77c","tags":[{"label":"typescript","permalink":"/blog/tags/typescript"},{"label":"setting","permalink":"/blog/tags/setting"},{"label":"doc","permalink":"/blog/tags/doc"}],"readingTime":1.66,"truncated":true,"authors":[{"name":"Eunju","title":"Front End Engineer","url":"https://github.com/eunchu","imageURL":"https://github.com/eunchu.png","key":"eunju"}],"frontMatter":{"slug":"typescript","title":"Typescript \uc815\ub9ac","authors":["eunju"],"tags":["typescript","setting","doc"]},"prevItem":{"title":"Javascript \uc774\ubca4\ud2b8 \uad00\ub9ac \ubc29\ubc95(\ubc84\ube14\ub9c1,\ucea1\ucc98\ub9c1,\uc704\uc784 \ub4f1)","permalink":"/blog/JSEvent"},"nextItem":{"title":"tsconfig \uc635\uc158 \uc815\ub9ac","permalink":"/blog/tsConfig"}},"content":"## Typescript\\n\\n> Javascript \uae30\ubc18\uc758 \ud504\ub85c\uadf8\ub798\ubc0d \uc5b8\uc5b4<br/>\\n>\\n> Typescript \ud50c\ub808\uc774\uadf8\ub77c\uc6b4\ub4dc (\ud0c0\uc785\uc2a4\ud06c\ub9bd\ud2b8 \ud14c\uc2a4\ud2b8)<br/>\\n> \ud83e\udd39\u200d\u2640\ufe0f https://www.typescriptlang.org/play\\n\\n\x3c!--truncate--\x3e\\n\\n## \uae30\ub2a5\\n\\n### 1. Optional Props\\n\\n\uac19\uc740 \uc18d\uc131\uc774 \ub2e4\ub978 \ub450 \uacf3\uc5d0\uc11c, \ud558\ub098\ub294 **\ud544\uc218** \ud558\ub098\ub294 **\uc635\uc154\ub110**\ud558\uac8c \uc801\uc6a9\ub420 \uacbd\uc6b0 Default\uac12\uc744 \uc9c0\uc815\ud560 \uc218 \uc788\ub2e4.\\n\\n```typescript\\ninterface AppProps {\\n\\tbg: string;\\n\\tborderColor?: string; //optional\ud55c \uac12\uc73c\ub85c string or undefined\\n}\\nfunction App({ bg, borderColor }: AppProps) {\\n\\treturn (\\n\\t\\t<Container>\\n\\t\\t\\t<Circle bgColor=\\"tomato\\" borderColor={borderColor ?? \\"white\\"}/>\\n\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t//undefined\uc77c \uacbd\uc6b0 white\uac12\uc744 \uc0ac\uc6a9\ud568\\n\\t\\t\\t<Circle bgColor=\\"tomato\\"/>\\n\\t\\t</Container>\\n\\t)\\n}\\n\\n// \uc704\uc640 \ub3d9\uc77c\ud568!\\nfunction App({ bg, borderColor = \\"white\\" }: AppProps) {\\n```\\n\\n### 2. Enums\\n\\n\uc5f4\uac70\ud615 \uc790\ub8cc\uad6c\uc870, `\uc11c\ub85c \uc5f0\uad00\ub41c \uc0c1\uc218\ub4e4\uc758 \uc9d1\ud560`\uc744 \uc815\uc758\ud560 \uc218 \uc788\ub2e4.<br />\\n\uc5f4\uac70\ud615\uc744 \uc774\uc6a9\ud558\uba74 \ub0b4\uc6a9\uc744 \ubb38\uc11c\ud654\ud558\uac70\ub098 \uad6c\ubd84\ub418\ub294 \uc0ac\ub840 \uc9d1\ud569\uc744 \ub354 \uc27d\uac8c \uad00\ub9ac\ud560 \uc218 \uc788\ub2e4.<br />\\n<br />\\n\\n- \ud0c0\uc785\uc2a4\ud06c\ub9bd\ud2b8\ub294 \uc22b\uc790\uc640 \ubb38\uc790\uc5f4 \uae30\ubc18 \uc5f4\uac70\ud615\uc744 \uc81c\uacf5\ud568\\n\\n```typescript\\nexport enum Categories {\\n  \\"TO_DO\\",\\n  \\"DOING\\",\\n  \\"DONE\\",\\n}\\n\\nexport const categoryState = atom<IToDo[\\"category\\"]>({\\n  key: \\"category\\",\\n  default: Categories.TO_DO, // \ud83d\udc48\\n});\\n```\\n\\n**\uc0ac\uc6a9\uc2dc \uc774\uc810**\\n\\n- \uad00\ub9ac \ud3ec\uc778\ud2b8\uac00 \ud55c \uacf3\uc774\ub77c, \uc218\uc815\uc5d0 \uc6a9\uc774\ud568!\\n- \uac19\uc740 \ubb38\uc790 \ubc18\ubcf5\ud574\uc11c \uc4f8 \ud544\uc694\ub3c4 \uc5c6\uc5b4\uc9c0\uace0, \uc5d0\ub7ec(\uc624\ud0c0/\uc2e4\uc218) \ubc29\uc9c0\ud560 \uc218 \uc788\uc74c\\n\\n### 3. string to number\\n\\n```typescript\\n1.\\nconst a = \\"123\\";\\nconst b = +a;\\n// b -> 123\\n\\n2. js\\nNumber(b);\\n```"},{"id":"tsConfig","metadata":{"permalink":"/blog/tsConfig","editUrl":"https://github.com/eunchu/blog/tree/main/blog/2022-06-03-tsconfig/index.md","source":"@site/blog/2022-06-03-tsconfig/index.md","title":"tsconfig \uc635\uc158 \uc815\ub9ac","description":"tsconfig.json \uc635\uc158 \uc815\ub9ac","date":"2022-06-03T00:00:00.000Z","formattedDate":"2022\ub144 6\uc6d4 3\uc77c","tags":[{"label":"typescript","permalink":"/blog/tags/typescript"},{"label":"setting","permalink":"/blog/tags/setting"},{"label":"doc","permalink":"/blog/tags/doc"}],"readingTime":1.255,"truncated":true,"authors":[{"name":"Eunju","title":"Front End Engineer","url":"https://github.com/eunchu","imageURL":"https://github.com/eunchu.png","key":"eunju"}],"frontMatter":{"slug":"tsConfig","title":"tsconfig \uc635\uc158 \uc815\ub9ac","authors":["eunju"],"tags":["typescript","setting","doc"]},"prevItem":{"title":"Typescript \uc815\ub9ac","permalink":"/blog/typescript"},"nextItem":{"title":"Recoil vs Redux \ube44\uad50\uc640 \uc0c1\ud0dc\uad00\ub9ac \ub77c\uc774\ube0c\ub7ec\ub9ac \uc120\ud0dd","permalink":"/blog/recoilVSredux"}},"content":"## tsconfig.json \uc635\uc158 \uc815\ub9ac\\n\\n\x3c!--truncate--\x3e\\n\\n```json\\n{\\n  \\"compilerOptions\\": {\\n    // [\uae30\ubcf8 \uc635\uc158]\\n    \\"baseUrl\\": \\".\\",\\n    \\"paths\\": {\\n      \\"@components/*\\": [\\"components/*\\"],\\n      \\"@styles/*\\": [\\"styles/*\\"],\\n      \\"@store/*\\": [\\"store/*\\"]\\n    },\\n    // ECMAScript \ubc84\uc804 \uc124\uc815\\n    \\"target\\": \\"es6\\",\\n    // \ubaa8\ub4c8\uc744 \uc704\ud55c \ucf54\ub4dc \uc0dd\uc131 \uc124\uc815\\n    \\"module\\": \\"commonjs\\",\\n    // \ucef4\ud30c\uc77c\uc5d0 \ud3ec\ud568\ub420 \ub77c\uc774\ube0c\ub7ec\ub9ac \ud30c\uc77c \ubaa9\ub85d\\n    \\"lib\\": [\\"dom\\", \\"dom.iterable\\", \\"esnext\\"],\\n    // js\ud30c\uc77c \ucef4\ud30c\uc77c \ud5c8\uc6a9 \uc5ec\ubd80\\n    \\"allowJs\\": true,\\n    // .js\ud30c\uc77c\uc758 \uc624\ub958 \uac80\uc0ac \uc5ec\ubd80\\n    \\"checkJs\\": true,\\n    // .map \ud30c\uc77c \uc0dd\uc131 \uc5ec\ubd80\\n    \\"sourceMap\\": true,\\n    // \uc8fc\uc11d \uc0ad\uc81c \uc5ec\ubd80\\n    \\"removeComments\\": true,\\n    // \uacb0\uacfc \ud30c\uc77c \ub0b4\ubcf4\ub0bc\uc9c0 \uc5ec\ubd80\\n    \\"noEmit\\": true,\\n    // \uac01 \ud30c\uc77c\uc744 \ubd84\ub9ac\ub41c \ubaa8\ub4c8\ub85c \ud2b8\ub79c\uc2a4\ud30c\uc77c\\n    \\"isolatedModules\\": true,\\n\\n\\n    // [\ud0c0\uc785 \uccb4\ud0b9]\\n    // \uc5c4\uaca9\ud55c \ud0c0\uc785 \uccb4\ud0b9 \uc635\uc158\\n    \\"strict\\": true,\\n\\n    \\"esModuleInterop\\": true,\\n    \\"module\\": \\"esnext\\",\\n    // \ubaa8\ub4c8 \ud574\uc11d \ubc29\ubc95 \uc124\uc815\\n    \\"moduleResolution\\": \\"node\\",\\n    \\"resolveJsonModule\\": true,\\n    \\"jsx\\": \\"preserve\\",\\n    // \uc99d\ubd84 \ucef4\ud30c\uc77c \uc124\uc815 \uc5ec\ubd80\\n    \\"incremental\\": true\\n\\n    // \uc815\uc758 \ud30c\uc77c\uc758 \ud0c0\uc785 \ud655\uc778 \uac74\ub108 \ub6f8 \uc9c0 \uc5ec\ubd80\\n    \\"skipLibCheck\\": true,\\n    // \uac19\uc740 \ud30c\uc77c\uc5d0 \ub300\ud55c \uc77c\uad00\ub418\uc9c0 \uc54a\uc740 \ucc38\uc870 \ud5c8\uc6a9 \uc5ec\ubd80\\n    \\"forceConsistentCasingInFileNames\\": true,\\n  },\\n  \\"include\\": [\\"next-env.d.ts\\", \\"**/*.ts\\", \\"**/*.tsx\\"],\\n  \\"exclude\\": [\\"node_modules\\"]\\n}\\n```\\n\\n[\ub354 \ub9ce\uc740 \uc635\uc158!](https://aka.ms/tsconfig.json)"},{"id":"recoilVSredux","metadata":{"permalink":"/blog/recoilVSredux","editUrl":"https://github.com/eunchu/blog/tree/main/blog/2022-06-02-recoilVSredux/index.md","source":"@site/blog/2022-06-02-recoilVSredux/index.md","title":"Recoil vs Redux \ube44\uad50\uc640 \uc0c1\ud0dc\uad00\ub9ac \ub77c\uc774\ube0c\ub7ec\ub9ac \uc120\ud0dd","description":"Overview","date":"2022-06-02T00:00:00.000Z","formattedDate":"2022\ub144 6\uc6d4 2\uc77c","tags":[{"label":"react","permalink":"/blog/tags/react"},{"label":"recoil","permalink":"/blog/tags/recoil"},{"label":"redux","permalink":"/blog/tags/redux"},{"label":"\uc0c1\ud0dc\uad00\ub9ac","permalink":"/blog/tags/\uc0c1\ud0dc\uad00\ub9ac"}],"readingTime":5.32,"truncated":true,"authors":[{"name":"Eunju","title":"Front End Engineer","url":"https://github.com/eunchu","imageURL":"https://github.com/eunchu.png","key":"eunju"}],"frontMatter":{"slug":"recoilVSredux","title":"Recoil vs Redux \ube44\uad50\uc640 \uc0c1\ud0dc\uad00\ub9ac \ub77c\uc774\ube0c\ub7ec\ub9ac \uc120\ud0dd","authors":["eunju"],"tags":["react","recoil","redux","\uc0c1\ud0dc\uad00\ub9ac"]},"prevItem":{"title":"tsconfig \uc635\uc158 \uc815\ub9ac","permalink":"/blog/tsConfig"},"nextItem":{"title":"\ub9ac\uc561\ud2b8 \uc0c1\ud0dc\uad00\ub9ac \ubcc0\uacbd\uc5d0 \ub300\ud55c \uc81c\uc548","permalink":"/blog/reactState"}},"content":"## Overview\\n\\n\ub2e4\ub978 \ud504\ub85c\uc81d\ud2b8\uc5d0 \ud22c\uc785\ub418\uba74\uc11c \uc544\ud0a4\ud14d\uccd0 \uc124\uacc4\ubd80\ud130 \ub300\ub300\uc801\uc778 \uc218\uc815\uc774 \ud544\uc694\ud574\uc84c\ub2e4.<br/>\\n\ub610 \uc2dc\uc791\ub418\ub294 **\ub9ac\ud329\ud1a0\ub9c1** \ud83e\udd73<br/>\\n\uae30\uc874\uc758 \uc0c1\ud0dc\uad00\ub9ac \ubc29\uc2dd\uc5d0\uc11c \ub9d8\uc5d0 \uc548\ub4e4\uc5c8\ub358 \uc810\ub3c4 \uace0\uce60\uacb8! \uc774\ubc88 \ud504\ub85c\uc81d\ud2b8\uc758 \ub808\uac70\uc2dc \ucf54\ub4dc\ub3c4 \ub300\uac70 \uac77\uc5b4\ub0bc\uacb8<br/>\\n\uae30\uc874 \ud504\ub85c\uc81d\ud2b8\uc5d0\uc11c \uc0ac\uc6a9\uc911\uc774\uc5c8\ub358 **[Redux](https://ko.redux.js.org/)**\uc640 \uc0c1\ud0dc\uad00\ub9ac \uccb4\uacc4\uac00 \ubcc0\uacbd\ub418\uba74\uc11c \uc0ac\uc6a9\ud558\uae30 \uc801\ud569\ud558\ub2e4\uace0 \ud310\ub2e8\ub418\ub294<br/>\\n**[Recoil](https://recoiljs.org/ko/)**\ub97c \ube44\uad50\ud574\ubcf4\uace0\\n\ud300\uc6d0\ub4e4\uacfc \uacf5\uc720 \ud6c4 \uc120\ud0dd\ub418\ub294 \ubc29\ud5a5\uc73c\ub85c \uc0c1\ud0dc\uccb4\uc81c\ub97c \uad6c\uc131\ud574\ubcf4\ub824\uace0 \ud55c\ub2e4.\ud83d\ude4c\\n\\n\x3c!--truncate--\x3e\\n\\n## Recoil vs Redux\\n\\n### 1. \ube44\uad50\\n\\n|          | Recoil                                                                                           | Redux                                                                                   |\\n| -------- | ------------------------------------------------------------------------------------------------ | --------------------------------------------------------------------------------------- |\\n| \ucee8\uc149     | Atomic \ubaa8\ub378 \uae30\ubc18<br/> : \uc791\uc740 \uc0c1\ud0dc \ub2e8\uc704(atom)\ub85c \uad00\ub9ac,<br/> atom\uc744 \uacb0\ud569\ud558\uc5ec \ub370\uc774\ud130\ub97c \uac00\uacf5\ud558\ub294 \ubc29\uc2dd | Flux \uc544\ud0a4\ud14d\uccd0 \uae30\ubc18<br/> : \ub2e8\ubc29\ud5a5 \ub370\uc774\ud130 \ud750\ub984<br/> action -> dispatcher -> store -> view |\\n| \ubbf8\ub4e4\uc6e8\uc5b4 | X                                                                                                | O                                                                                       |\\n| \ucf54\ub4dc\ub7c9   | \u2191                                                                                                | \u2193                                                                                       |\\n| \ubcf5\uc7a1\ub3c4   | \uc911\ud558                                                                                             | \uc911\uc0c1                                                                                    |\\n| DevTools | \ubbf8\ud761                                                                                             | Good                                                                                    |\\n| \uad00\ub9ac\ubc29\uc2dd | \ubd84\uc0b0\uad00\ub9ac                                                                                         | \uc911\uc559\uc9d1\uc911\ud615                                                                              |\\n\\n### 2. Recoil \ud2b9\uc9d5\\n\\n- \ub3d9\uc2dc\uc131 \ubaa8\ub4dc \uc81c\uacf5\\n  - Concurrent mode: \ud750\ub984\uc774 \uc5ec\ub7ec \uac1c\uac00 \uc874\uc7ac\ud558\ub294 \uacbd\uc6b0, \ub80c\ub354\ub9c1 \ub3c5\uc791 \uc6b0\uc120\uc21c\uc704\ub97c \uc815\ud558\uc5ec \ub80c\ub354\ub9c1\ud560 \uc218 \uc788\uc74c\\n- `atom -> selector -> components` \ud50c\ub85c\uc6b0\uc758 \ubcf5\uc7a1\ud558\uc9c0 \uc54a\uc740 \uad6c\uc870\\n- \ub9ac\uc561\ud2b8\ub97c \uc704\ud55c \ub9de\ucda4 \uc0c1\ud0dc\uad00\ub9ac \ub77c\uc774\ube0c\ub7ec\ub9ac\\n- \ub0ae\uc740 \ub7ec\ub2dd\ucee4\ube0c\\n- `store`\uc640 \uac19\uc740 \uc678\ubd80 \uc694\uc778\uc774 \uc544\ub2cc `react`\ub0b4\ubd80\uc758 \uc0c1\ud0dc\ub97c \ud65c\uc6a9\ud558\uace0 `contextAPI`\ub97c \ud1b5\ud574 \uad6c\ud604\ub418\uc5b4 \uc788\uae30 \ub54c\ubb38\uc5d0 \ub9ac\uc561\ud2b8 \uc2a4\ub7ec\uc6b4 \uc0c1\ud0dc\uad00\ub9ac\uac00 \uac00\ub2a5\ud568\\n- \ub9ac\uc561\ud2b8 \ub0b4\uc7a5 `hooks`\ub97c \uc0ac\uc6a9\ud558\ub294 \ubc29\uc2dd\uacfc \uac70\uc758 \ub611\uac19\uae30 \ub54c\ubb38\uc5d0 \uc27d\uac8c \ubc30\uc6b0\uace0 \ud65c\uc6a9\ud560 \uc218 \uc788\uc74c\\n\\n### 3. Redux \ud2b9\uc9d5\\n\\n- Single source of truth\\n  - \uac19\uc740 \ub370\uc774\ud130\ub294 \ud56d\uc0c1 \uac19\uc740 \uc7a5\uc18c\uc5d0\uc11c \uad00\ub9ac\\n- \uc0c1\ud0dc \ubcc0\uacbd\uc740 \uc21c\uc218\ud568\uc218\ub85c\ub9cc \uac00\ub2a5\ud568\\n- \ube0c\ub77c\uc6b0\uc800 Devtools\ub97c \ud65c\uc6a9\ud558\uc5ec \ud604\uc7ac \uc0c1\ud0dc\ub97c \uad00\ub9ac\ud558\uae30 \ud3b8\ud568\\n- \uc911\uc559\uc9d1\uc911\ud615 store\uad00\ub9ac\ub85c \ub85c\uc9c1 \ubcf5\uc7a1\ub3c4\uac00 \ub192\uc740 \ud3b8\uc784\\n\\n---\\n\\n## Recoil\\n\\n### \ud2b9\uc7a5\uc810\\n\\n- `atom \u2192 selector \u2192 component` \uc758 \ud558\ub098\uc758 `data-flow`\\n- `Concurrent Mode` \uc9c0\uc6d0\\n- **\uce90\uc2f1\uc9c0\uc6d0**\\n  - selector\ub97c \ud1b5\ud55c \ube44\ub3d9\uae30 \uc791\uc5c5\uc744 \uc9c4\ud589\ud560 \ub54c, atom\uac12\uc5d0 \uc790\ub3d9\uc73c\ub85c \uc758\uc874\uc131\uc774 \uac78\ub9ac\ub294\ub370\\n    atom\uac12\uc774 \ubcc0\uacbd\ub420 \ub54c\ub9c8\ub2e4 selector\uac00 \ubcc0\uacbd\ub41c\ub2e4. \uc774\ub54c atom\uc758 \uac12\uc774 \ub3d9\uc77c\ud560 \uacbd\uc6b0 \ub0b4\ubd80\uc801\uc73c\ub85c\\n    \ubc18\ud658\uac12\uc744 \uba54\ubaa8\ub77c\uc774\uc988 \ud558\uace0 \uc788\uc5b4 \uce90\uc2f1\ub41c \uac12\uc744 \ubc18\ud658\ud568\\n- `useRecoilValue`\ub97c \uc0ac\uc6a9\ud558\uba74 state, set\uc744 \ubc18\ud658\ud574\uc90c try,catch\uad6c\ubb38\uc744 \uc0ac\uc6a9\ud558\uc9c0 \uc54a\uc544\ub3c4 \ub428\\n\\n### Atom\\n\\n- \uc0c1\ud0dc\uc758 \ub2e8\uc704\\n- atom\uc774 \uc5c5\ub370\uc774\ud2b8\ub418\uba74 \ud574\ub2f9 atom\uc744 \uad6c\ub3c5\ud558\uace0 \uc788\ub358 \ubaa8\ub4e0 \ucef4\ud3ec\ub10c\ud2b8\uc758 \uc0c1\ud0dc\uac00 \uac31\uc2e0\ub418\uc5b4 \ub9ac\ub79c\ub354\ub428\\n- unique\ud55c key\uac12\uc73c\ub85c \uad6c\ubd84\ud568\\n\\n### useRecoilState\\n\\n```typescript\\nconst [value, setValue] = useRecoilState(valueState);\\n```\\n\\n`useRecoilState` hook\uc744 \uc0ac\uc6a9\ud574\uc11c `state`\ub97c `get`, `set`\ud560 \uc218 \uc788\uc74c<br />\\n**react\uc758 useState\uc640 \ub3d9\uc77c\ud55c \uc0ac\uc6a9\ubc29\uc2dd**\\n\\n### useRecoilValue, useSetRecoilValue\\n\\n```typescript\\nconst value = useRecoilValue(valueState);\\nconst setValue = useSetRecoilValue(valueState);\\n```\\n\\nvalue, \ubcc0\uacbd\ud568\uc218 \uac01\uac01 \ub530\ub85c \ud638\ucd9c\ud558\uc5ec \uc4f8 \uc218 \uc788\uc74c\\n\\n### Selector\\n\\n\ub2e4\ub978 selector, atom\uc758 \uac12\uc744 get\ud574\uc62c \uc218 \uc788\uace0 \uadf8 \uac12\uc744 \ubc14\ud0d5\uc73c\ub85c state\ub97c modify\ud558\ub294 \uc5ed\ud560\\n\\n```typescript\\nconst countState = selector({\\n  key: \\"countState\\", // uniqueId\\n  get: ({ get }) => {\\n    const text = get(textState);\\n    return text.length;\\n  },\\n  set: ({ set }, newValue) => {\\n    // newValue => \ubcc0\uacbd \ub41c \uc0c1\ud0dc \uac12\\n  },\\n});\\n```\\n\\n- \ud30c\uc0dd\ub41c `state`\ub97c \ub9cc\ub4e4 \uc218 \uc788\uc74c\\n- `get`\ud504\ub85c\ud37c\ud2f0\ub97c \ud1b5\ud574 `state`\ub97c \uac00\uacf5\ud558\uc5ec \ubc18\ud658\ud560 \uc218 \uc788\uc74c\\n- \uc21c\uc218\ud568\uc218\uc5ec\uc57c \ud568\\n- \uae30\ubcf8\uc801\uc73c\ub85c \uac12\uc744 \uce90\uc2f1\ud568 (\ud55c\ubc88 call\ud55c api\uc5d0 \ub300\ud574\uc11c \uc0c8\ub85c\uc6b4 call\uc774 \ud544\uc694 \uc5c6\uc74c)\\n\\n---\\n\\n## \uacb0\ub860\\n\\n1. \uc0c1\ud0dc\uad00\ub9ac \ubcc0\uacbd\uc758 \ud544\uc694\uc131\\n2. \ub2e4\ub978 \ub77c\uc774\ube0c\ub7ec\ub9ac\uc758 \ub3c4\uc785\\n\\n   \ub450 \uac00\uc9c0 \ubaa8\ub450 \ud544\uc694\ud55c \ubd80\ubd84\uc774\uace0 \ud604 \ud504\ub85c\uc81d\ud2b8\uc758 \ubb38\uc81c\uc810\uc744 \ud574\uacb0\ud560 \uc218 \uc788\uc73c\uba70<br />\\n   \uac04\ub2e8\ud55c \uac1c\ub150\uc73c\ub85c\ub3c4 \uc27d\uac8c \uc811\uadfc\ud560 \uc218 \uc788\ub294 recoil\uc758 \ub3c4\uc785\uc744 \uacb0\uc815.<br />\\n   \uc2ec\uc9c0\uc5b4 \ub9ce\uc740 \ubcf4\uc77c\ub7ec \ud50c\ub808\uc774\ud2b8 \ucf54\ub4dc\ub4e4\uc744 \uc904\uc77c \uc218 \uc788\ub2e4.<br />\\n   \ub300\ud615 \ud504\ub85c\uc81d\ud2b8\uc5d0\uc11c\uc758 \uad00\ub9ac\uc5d0 \ub300\ud55c \ub808\ud37c\ub7f0\uc2a4\ub294 \ub9ce\uc9c0 \uc54a\uc9c0\ub9cc, \uc2dc\uac04\uc744 \ud22c\uc790\ud558\uc5ec \uc801\uc6a9\ud560 \uac00\uce58\uac00 \uc788\ub2e4\uace0 \ud310\ub2e8\ub428"},{"id":"reactState","metadata":{"permalink":"/blog/reactState","editUrl":"https://github.com/eunchu/blog/tree/main/blog/2022-06-01-reactState/index.md","source":"@site/blog/2022-06-01-reactState/index.md","title":"\ub9ac\uc561\ud2b8 \uc0c1\ud0dc\uad00\ub9ac \ubcc0\uacbd\uc5d0 \ub300\ud55c \uc81c\uc548","description":"Overview","date":"2022-06-01T00:00:00.000Z","formattedDate":"2022\ub144 6\uc6d4 1\uc77c","tags":[{"label":"react","permalink":"/blog/tags/react"},{"label":"recoil","permalink":"/blog/tags/recoil"},{"label":"react-query","permalink":"/blog/tags/react-query"},{"label":"\uc0c1\ud0dc\uad00\ub9ac","permalink":"/blog/tags/\uc0c1\ud0dc\uad00\ub9ac"}],"readingTime":3.78,"truncated":true,"authors":[{"name":"Eunju","title":"Front End Engineer","url":"https://github.com/eunchu","imageURL":"https://github.com/eunchu.png","key":"eunju"}],"frontMatter":{"slug":"reactState","title":"\ub9ac\uc561\ud2b8 \uc0c1\ud0dc\uad00\ub9ac \ubcc0\uacbd\uc5d0 \ub300\ud55c \uc81c\uc548","authors":["eunju"],"tags":["react","recoil","react-query","\uc0c1\ud0dc\uad00\ub9ac"]},"prevItem":{"title":"Recoil vs Redux \ube44\uad50\uc640 \uc0c1\ud0dc\uad00\ub9ac \ub77c\uc774\ube0c\ub7ec\ub9ac \uc120\ud0dd","permalink":"/blog/recoilVSredux"}},"content":"## Overview\\n\\n**\ud604 \ud504\ub85c\uc81d\ud2b8 \uc0c1\ud0dc\uad6c\uc870**\\n\uc804\uc5ed \uc0c1\ud0dc \uad00\ub9ac\ub97c \uc704\ud574 `ContextAPI`\ub97c \uc0ac\uc6a9\ud558\uace0 \uc788\uc73c\uba70,\\n\ub85c\uceec \uc0c1\ud0dc\ub294 \uac01 \ucef4\ud3ec\ub10c\ud2b8\uc5d0\uc11c \uc0ac\uc6a9\ub418\ub294 \uc0c1\ud0dc\ub9cc \uac01\uc790(\uac01 \ucef4\ud3ec\ub10c\ud2b8\uc5d0\uc11c) \uad00\ub9ac\ud558\uace0 \uc788\ub2e4.<br/>\\n\ud504\ub85c\uc81d\ud2b8 \uaddc\ubaa8\uac00 \ucee4\uc9c0\uba74\uc11c, \ucef4\ud3ec\ub10c\ud2b8\uc5d0 \ub85c\uceec \uc0c1\ud0dc\uacfc \ube44\ub3d9\uae30 \ud1b5\uc2e0\uc774 \ud63c\uc7ac\ub418\uace0 \ubcf5\uc7a1\ub3c4\uac00 \ub192\uc544\uc9c0\uace0 \uc788\ub2e4.<br/>\\n\uc804\uc5ed, \ub85c\uceec, \uc11c\ubc84 \uc0c1\ud0dc\ub97c \uc5b4\ub5bb\uac8c \uad6c\ubd84\ud558\uace0 \uad00\ub9ac\ud560\uc9c0\uc5d0 \ub300\ud55c \uc124\uacc4\uac00 \ud544\uc694\ud558\ub2e4\uace0 \ud310\ub2e8\ub418\uc5b4 \uc544\ub798 \ub0b4\uc6a9\uc744 \uc81c\uc548\ud569\ub2c8\ub2e4\ud83e\udd1c\\n\\n> Local State: \ub9ac\uc561\ud2b8 \ucef4\ud3ec\ub10c\ud2b8 \uc548\uc5d0\uc11c\ub9cc \uc0ac\uc6a9\ub418\ub294 State<br />\\n> Global State: Global Store\uc5d0 \uc815\uc758\ub418\uc5b4 \ud504\ub85c\uc81d\ud2b8 \uc5b4\ub514\uc11c\ub098 \uc811\uadfc \uac00\ub2a5\ud55c State<br/>\\n> Server State: \uc11c\ubc84\ub85c\ubd80\ud130 \ubc1b\uc544\uc624\ub294 State\\n\\n\x3c!--truncate--\x3e\\n\\n## \ud604\uc7ac \uad6c\uc870\\n\\n**\uc804\uc5ed \uc0c1\ud0dc**\\n![\uc804\uc5ed\uc0c1\ud0dc](./01.png)\\n\\n**\ub85c\uceec\uc0c1\ud0dc**\\n![\ub85c\uceec\uc0c1\ud0dc](./02.png)\\n\\n## \u2714\ufe0f \ubb38\uc81c\uc810\\n\\n- BA\ucc98\ub7fc \ubcf5\uc7a1\ud55c \ud504\ub85c\uc81d\ud2b8\uc758 \uacbd\uc6b0 \ubc31\uc5ec\uac1c\uc758 api\ub3d9\uc791\ub9c8\ub2e4 \ubaa8\ub450 \uc751\ub2f5\uac12\uc744 \ubc14\ub77c\ubcf4\ub294 \uc0c1\ud0dc\ub4e4\uc774 \uc874\uc7ac\ud558\uace0 \uc774\ub7ec\ud55c \uac83\ub4e4\uc774 \uc804\uc5ed \uc0c1\ud0dc\uc640 \ucef4\ud3ec\ub10c\ud2b8 \ub0b4\ubd80\uc5d0 \uc0b0\uc7ac\ub418\uc5b4 \uc788\ub2e4.\\n- \ucd94\uac00\ub85c api\uc5d0\uc11c \ubc1b\uc740 \ub370\uc774\ud130\uc758 \uc870\uc791\uacfc \uac00\uacf5\ub41c \uc0c1\ud0dc\uae4c\uc9c0 \uc874\uc7ac\ud568\uc5d0\ub530\ub77c \uc0c1\ud0dc\uad00\ub9ac\uc758 \ubcf5\uc7a1\ub3c4\uac00 \uc99d\uac00\ub418\uace0 \uc788\ub2e4.\\n  \uc774\ub7ec\ud55c \ubc29\uc2dd\uc774 \uc720\uc9c0\ub418\uba74 \uc0c1\ud0dc\uad00\ub9ac\uac00 \uc5b4\ub835\uace0, \ubcf5\uc7a1\ub3c4\ub9cc \ub298\uc5b4\uac08 \uac83\uc73c\ub85c \uc0dd\uac01\ub429\ub2c8\ub2e4.\\n\\n\uc804\uc5ed \uc0c1\ud0dc\uc640 \ube44\ub3d9\uae30 \ud1b5\uc2e0\uc5d0 \ub530\ub978 \uc0c1\ud0dc\uac00 \ubd84\ub9ac\ub418\uc57c\ud558\uace0 \uac01 \ucef4\ud3ec\ub10c\ud2b8 \ub0b4\ubd80\uc5d4 client side\uc758 \uc0c1\ud0dc\ub9cc\\n\uad00\ub9ac\ub420 \ud544\uc694\uc131\uc774 \uc788\ub2e4\uace0 \ubcf4\uc5ec\uc9d0\\n\\n## \ud83d\udd8d\xa0\ud574\uacb0 \ud3ec\uc778\ud2b8\\n\\n- \uc804\uc5ed \uc0c1\ud0dc \uad00\ub9ac\uc5d0\uc11c \ube44\ub3d9\uae30 \ud1b5\uc2e0\uc744 \uac77\uc5b4\ub0b4\uc57c \ud568\\n- \uc11c\ubc84 \uad00\ub828 \uc0c1\ud0dc\ub97c \ubcc4\ub3c4\ub85c \uad00\ub9ac\ud558\ub418 \uc804\uc5ed \uc0c1\ud0dc\ub85c \ud65c\uc6a9\ub420 \uc218 \uc788\uc5b4\uc57c \ud568\\n- \ucef4\ud3ec\ub10c\ud2b8 \uac1c\ubcc4\ub2e8\uc704\uc758 \uc0c1\ud0dc\ub294 \uc720\uc9c0\ud558\ub418 \ub9c8\ucc2c\uac00\uc9c0\ub85c \ube44\ub3d9\uae30 \ud1b5\uc2e0\uc744 \uac77\uc5b4\ub0b4\uc57c \ud568\\n\\n## \ud83e\uddd0\xa0\ubc29\uc548 \uc81c\uc2dc\\n\\n**React Query\uc758 \ub3c4\uc785**\\n\\n[React Query](https://react-query.tanstack.com/)\ub780<br/>\\n: Server\uc640 client \uc0ac\uc774 \ube44\ub3d9\uae30 \ub85c\uc9c1\uc744 \uc27d\uac8c \ub2e4\ub8e8\uac8c \ud574\uc8fc\ub294 \ub77c\uc774\ube0c\ub7ec\ub9ac\\n\\n### React-query \ud2b9\uc9d5&\uac15\uc810\\n\\n1. \uac04\uacb0\ud55c \ucf54\ub4dc\\n\\n- saga\ucc98\ub7fc \ube44\ub3d9\uae30 \uad00\ub828 \ub85c\uc9c1\uc774 \uc7a5\ud669\ud558\uc9c0 \uc54a\uc74c\\n- `useQuery`\ub97c \ud1b5\ud574 \uace0\uc720\ud55c key\uac12\uc73c\ub85c \uad6c\ubd84\ub418\uba70, \uc5ec\ub7ec \ucffc\ub9ac\ub97c \ucef4\ud3ec\ub10c\ud2b8 \uacf3\uacf3\uc5d0 \ubfcc\ub824\ub46c\ub3c4 \ub3d9\uc77c\ud55c \ub370\uc774\ud130\uc5d0 \uc811\uadfc \uac00\ub2a5\\n- \ucf54\ub4dc \uae38\uc774\uac00 \uc9e7\uc544\uc9c0\uace0 \uac00\ub3c5\uc131\ub3c4 \uc88b\uc74c\\n- \uc0c1\ud0dc \uc800\uc7a5 \ud544\uc694\uc5c6\uc774 \ubc14\ub85c \uc0ac\uc6a9 \uac00\ub2a5\\n\\n```typescript\\n// React-query\uc608\uc2dc\\nconst { data, isLoading, isError, ... } = useQuery(\\"key\\", fetchFc, { ...options });\\n\\nreturn (\\n  <ul>\\n    {data.map(item => (\\n      <li key={item.id}>{item.name}</li>\\n    ))}\\n  </ul>\\n)\\n```\\n\\n2. \ub3d9\uae30\ud654 \ubc0f \uc5c5\ub370\uc774\ud2b8\ub97c \ubcf4\ub2e4 \uc27d\uac8c \ucc98\ub9ac\ud560 \uc218 \uc788\uc74c\\n\\n## \uacb0\ub860/\uc81c\uc548\\n\\nLocal State: \uae30\uc874 \ubc29\uc2dd \uc720\uc9c0 (useState)<br />\\nGlobal State: Recoil, Mobx\uac19\uc774 \uc804\uc5ed\uad00\ub9ac\uc6a9 \ub77c\uc774\ube0c\ub7ec\ub9ac \uc368\uce58 \ubc0f \ub3c4\uc785 \ud544\uc694<br/>\\nServer State: React query\ub97c \uc0ac\uc6a9\ud558\uc5ec \ub85c\uceec\uc0c1\ud0dc\uc640 \ubd84\ub9ac\ud568"}]}')}}]);